INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('behavioral_general', 'Tell me about yourself.', 'Structure it as: current role + key achievement + why you want this role. Keep it to 60–90 seconds. Example: "I''m a software engineer with 4 years of experience building scalable APIs. Recently I led a migration that cut response time by 40%. I''m excited about this role because I want to work on product-level impact at scale."', 1),
('behavioral_general', 'What are your greatest strengths?', 'Pick 2–3 strengths tied to the role. Always back with a brief example. E.g. "Ownership — when our payment system went down at 2am, I didn''t wait for escalation. I diagnosed and fixed it within 90 minutes." Avoid generic words like "hardworking" without proof.', 2),
('behavioral_general', 'What is your greatest weakness?', 'Name a real weakness you have actively improved. Formula: weakness → what you did about it → current state. E.g. "I used to struggle with estimating timelines. I started breaking tasks into sub-tasks and tracking actuals vs estimates. My estimates are now within 15% of actuals."', 3),
('behavioral_general', 'Why do you want this job?', 'Three things: (1) something specific about the company/product you admire, (2) how the role matches your skill set, (3) how it helps your career growth. Research the company before answering. Generic "great culture" answers hurt you.', 4),
('behavioral_general', 'Where do you see yourself in 5 years?', 'Show ambition but stay realistic. Align with the company''s growth path. E.g. "I''d like to grow into a senior/lead engineer role, owning a critical system end-to-end. I''m drawn to this company because the technical challenges here would accelerate that path." Avoid saying "in your role" — it makes the interviewer nervous.', 5),
('behavioral_general', 'Tell me about a challenge you overcame.', 'Use STAR format: Situation, Task, Action, Result. Focus on YOUR actions, not the team''s. Quantify the result if possible. E.g. "Our app was crashing for 20% of Android users. I profiled crash reports, found a memory leak in our image loader, and patched it. Crash rate dropped to 0.3% within 24 hours."', 6),
('behavioral_general', 'Describe a time you worked in a difficult team.', 'Don''t blame teammates. Show that you adapted. Highlight communication and empathy. E.g. "One engineer would dismiss others'' suggestions. I had a 1:1 conversation, understood their concern, and we agreed on a hybrid solution. The team dynamic improved significantly."', 7),
('behavioral_general', 'How do you handle conflict at work?', 'Show you address it directly and professionally. Formula: acknowledge the conflict → one-on-one conversation → focus on the problem not the person → align on shared goal. Avoid saying "I avoid conflict" — that is a red flag to interviewers.', 8),
('behavioral_general', 'Tell me about a failure.', 'Interviewers want self-awareness and learning. Pick a real failure, own it fully (no blaming others), explain what you learned, and what you''d do differently. E.g. "I deployed a schema change without a rollback plan. It caused 2 hours of downtime. I now always write a rollback script before any DB migration and test it in staging."', 9),
('behavioral_general', 'Why are you leaving your current job?', 'Be positive. Acceptable reasons: want to grow into a different area, seeking bigger technical challenges, company direction changed, better culture fit. Never badmouth your current employer — interviewers assume you''ll do the same about them.', 10),
('behavioral_general', 'How do you handle pressure or tight deadlines?', 'Give a concrete example. Show that you prioritize, communicate early, and stay calm. E.g. "We had a 3-day deadline for a feature estimated at 2 weeks. I scoped it down to the must-haves, communicated tradeoffs to the PM, and shipped the core version on time. The rest shipped in the next sprint."', 11),
('behavioral_general', 'What motivates you?', 'Pick something genuine that is also relevant: solving hard problems, seeing users benefit from your work, learning new technologies, shipping impactful products. Avoid saying "money" even if true — say "I want to work on things that matter and where I can grow quickly."', 12),
('behavioral_general', 'Describe your leadership style.', 'Even if you are not a manager, you''ve likely led projects or mentored. Describe servant leadership: listen first, give context not commands, unblock others, take accountability. Back with an example if possible.', 13),
('behavioral_general', 'What are your salary expectations?', 'Research market rates beforehand (Glassdoor, Levels.fyi, LinkedIn). Give a range based on data: "Based on my research and experience, I''m looking at ₹X–Y LPA / $X–Y, but I''m flexible depending on the full package." Don''t lowball yourself — companies often pay more than the first number you say.', 14),
('behavioral_general', 'Do you have any questions for us?', 'Always ask 2–3 thoughtful questions. Good ones: "What does success look like in this role in the first 90 days?" / "What''s the biggest technical challenge the team is facing right now?" / "How does the team handle technical debt?" Never say "No, I think we covered everything."', 15);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('javascript', 'What is a closure?', 'A closure is a function that retains access to its outer scope even after the outer function has returned. Example: function counter() { let n = 0; return () => ++n; } — the returned arrow function closes over n. Used for data privacy, factory functions, and memoization.', 1),
('javascript', 'Explain the JavaScript event loop.', 'JS is single-threaded. The event loop checks: (1) call stack — runs synchronous code, (2) microtask queue — runs Promises/async callbacks after each task, (3) macrotask queue — runs setTimeout/setInterval. Microtasks always run before the next macrotask.', 2),
('javascript', 'What is the difference between var, let, and const?', 'var: function-scoped, hoisted to undefined, can be re-declared. let: block-scoped, not hoisted usably, cannot be re-declared. const: block-scoped, must be initialized, cannot be reassigned (but object properties can still be mutated). Prefer const by default, let when reassignment is needed, avoid var.', 3),
('javascript', 'What is a Promise?', 'A Promise represents a value that will be available in the future (pending → fulfilled/rejected). It avoids callback hell. fetch() returns a Promise. Chain with .then() / .catch() / .finally(). Create with new Promise((resolve, reject) => {}). Use Promise.all() for parallel async calls.', 4),
('javascript', 'Explain async/await.', 'async/await is syntactic sugar over Promises. An async function always returns a Promise. await pauses execution until the Promise resolves. Error handling uses try/catch. Cleaner than chaining .then(). Internally, await is like a yield in a generator managed by the JS engine.', 5),
('javascript', 'What is prototypal inheritance?', 'Every JS object has a prototype chain. When you access a property, JS looks up the chain until it finds it or reaches null. Objects inherit from other objects (not classes, though class syntax is sugar over this). Object.create(proto) explicitly sets the prototype.', 6),
('javascript', 'What is the difference between == and ===?', '=== (strict equality) checks value AND type — no coercion. 0 === ''0'' is false. == (loose equality) coerces types before comparing. 0 == ''0'' is true. Always use === unless you specifically need type coercion (rare). null == undefined is true; null === undefined is false.', 7),
('javascript', 'What is hoisting?', 'JavaScript moves declarations to the top of their scope during compilation. var declarations are hoisted and initialized to undefined. Function declarations are fully hoisted (callable before the line). let/const are hoisted but stay in the "temporal dead zone" — accessing them before declaration throws ReferenceError.', 8),
('javascript', 'What is the spread operator and rest parameter?', 'Spread (...arr) expands an iterable into individual elements: Math.max(...[1,2,3]), [...arr1, ...arr2]. Rest (...args) collects remaining function arguments into an array: function sum(...nums) { return nums.reduce((a,b)=>a+b,0); }. Same syntax, opposite purpose.', 9),
('javascript', 'What is destructuring?', 'Destructuring extracts values from arrays or objects into variables. Array: const [a, b] = [1, 2]. Object: const { name, age } = person. Rename: const { name: fullName } = person. Default values: const { x = 0 } = {}. Useful in function parameters: function f({ id, title }) {}.', 10),
('javascript', 'What is event bubbling and capturing?', 'When an event fires on an element, it propagates: capturing phase (top → element) then bubbling phase (element → top). By default, addEventListener uses bubbling. Use event.stopPropagation() to stop it. event.target is the actual clicked element; event.currentTarget is the element the listener is on.', 11),
('javascript', 'What is the difference between null and undefined?', 'undefined: variable declared but not assigned a value (default). null: explicitly set to represent "no value". typeof undefined === "undefined"; typeof null === "object" (a legacy JS bug). Use null when you want to intentionally clear a value; undefined usually means something was not set.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('python', 'What is a generator in Python?', 'A generator is a function that yields values one at a time using the yield keyword, maintaining its state between calls. It returns an iterator without storing all values in memory. Useful for large datasets. Example: def count_up(n): while True: yield n; n+=1. Use next() or a for loop to consume it.', 1),
('python', 'What is a decorator?', 'A decorator is a function that wraps another function to extend its behavior without modifying it. Syntax: @my_decorator above a function definition. Commonly used for logging, authentication, caching. Example: @functools.lru_cache() memoizes a function. Decorators are just higher-order functions.', 2),
('python', 'What is the GIL?', 'The Global Interpreter Lock (GIL) is a mutex in CPython that ensures only one thread executes Python bytecode at a time, even on multi-core systems. This makes multi-threading safe for I/O-bound tasks but limits CPU-bound parallelism. Solution for CPU-bound work: use multiprocessing, not threading.', 3),
('python', 'What is the difference between a list and a tuple?', 'List: mutable, defined with [], can add/remove elements. Tuple: immutable, defined with (), cannot be changed after creation. Tuples are faster and hashable (can be dict keys or set elements). Use tuples for fixed data (coordinates, DB records), lists for collections that change.', 4),
('python', 'What are *args and **kwargs?', '*args collects extra positional arguments into a tuple. **kwargs collects extra keyword arguments into a dict. Example: def f(*args, **kwargs): print(args, kwargs). f(1,2, name=''Alice'') → (1,2) {''name'':''Alice''}. Used to write flexible APIs that accept any number of arguments.', 5),
('python', 'What is list comprehension?', 'A concise way to create lists: [expression for item in iterable if condition]. Example: squares = [x**2 for x in range(10) if x%2==0]. Faster and more Pythonic than a for loop with append(). Also works for dicts: {k:v for k,v in items} and sets: {x for x in lst}.', 6),
('python', 'What is a lambda function?', 'A lambda is an anonymous inline function: lambda arguments: expression. Example: square = lambda x: x**2. Used for short operations passed to map(), filter(), sorted(). For anything more than one expression, use a regular def. Lambda is a style choice, not a performance win.', 7),
('python', 'Explain Python''s memory management.', 'Python uses reference counting (object deleted when count hits 0) plus a cyclic garbage collector for circular references. Memory is managed by the Python memory manager in private heaps. Developers do not call free() — it is automatic. The gc module lets you force a collection.', 8),
('python', 'What is the difference between __init__ and __new__?', '__new__ is called first and creates the instance (returns it). __init__ is called after and initializes the instance''s attributes (receives it as self). Normally you only override __init__. Override __new__ only when subclassing immutable types like int or str, or for singleton patterns.', 9),
('python', 'What is a context manager and the with statement?', 'A context manager manages setup and teardown. with open(''file'') as f: automatically closes the file even if an exception occurs. Implement one with __enter__ and __exit__ methods, or use @contextmanager decorator with yield. Cleaner than try/finally for resource management.', 10),
('python', 'Explain map, filter, and reduce.', 'map(func, iter): applies func to every element, returns iterator. filter(func, iter): keeps elements where func returns True. reduce(func, iter): from functools, folds elements left to right using func. Example: reduce(lambda a,b: a+b, [1,2,3]) → 6. List comprehensions are often preferred over map/filter.', 11),
('python', 'What is the difference between deep copy and shallow copy?', 'Shallow copy (copy.copy or list[:]) copies the object but not nested objects — inner objects are still shared references. Deep copy (copy.deepcopy) recursively copies everything. Example: if you shallow-copy a list of lists and modify an inner list, the original also changes.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('java', 'What are the four pillars of OOP?', 'Encapsulation: bundling data + methods, hiding internals with access modifiers. Inheritance: child class extends parent (extends keyword). Polymorphism: same method name behaves differently (method overriding at runtime, overloading at compile time). Abstraction: hiding implementation details behind interfaces/abstract classes.', 1),
('java', 'What is the difference between JVM, JRE, and JDK?', 'JVM (Java Virtual Machine): runs bytecode, platform-specific, handles memory/GC. JRE (Java Runtime Environment): JVM + standard libraries, needed to run Java programs. JDK (Java Development Kit): JRE + compiler (javac) + tools, needed to develop Java programs. To run: JRE. To develop: JDK.', 2),
('java', 'What is the difference between abstract class and interface?', 'Abstract class: can have constructors, instance fields, concrete methods, single inheritance only. Interface: all methods public abstract by default (Java 8+ allows default/static methods), no instance fields, a class can implement multiple interfaces. Use interface for a contract; abstract class when sharing code between related classes.', 3),
('java', 'What is the difference between == and .equals() in Java?', '== compares references (memory addresses) for objects. .equals() compares content/value. String s1 = new String("hi"); String s2 = new String("hi"); s1==s2 is false, s1.equals(s2) is true. For primitives, == compares values. Always use .equals() for String comparison.', 4),
('java', 'Explain Java garbage collection.', 'The JVM automatically reclaims memory for objects with no references. The heap is divided into Young Generation (new objects, frequent GC) and Old Generation (long-lived objects, less frequent GC). GC algorithms: Serial, Parallel, G1 (default in Java 9+), ZGC. System.gc() is a hint only — not guaranteed.', 5),
('java', 'What is multithreading in Java?', 'Running multiple threads concurrently to use CPU cores efficiently. Create via Thread class (extend or pass Runnable). Use ExecutorService for thread pools. Synchronize shared data with synchronized keyword or java.util.concurrent locks. Key risks: deadlock, race conditions, visibility issues (use volatile or AtomicInteger).', 6),
('java', 'What are Java Collections?', 'The Collections Framework provides data structures: List (ArrayList, LinkedList — ordered, allows duplicates), Set (HashSet, TreeSet — no duplicates), Map (HashMap, TreeMap — key-value pairs), Queue (LinkedList, PriorityQueue). Use generics: List<String>. Collections.sort() and Collections.unmodifiableList() are common utility methods.', 7),
('java', 'What is exception handling in Java?', 'Use try-catch-finally. Checked exceptions (IOException, SQLException): must be caught or declared with throws. Unchecked exceptions (RuntimeException, NullPointerException): do not need to be declared. finally always runs. try-with-resources auto-closes resources. Throw custom exceptions by extending Exception.', 8),
('java', 'What is the Singleton design pattern?', 'Ensures only one instance of a class exists. Thread-safe implementation: private constructor, private static instance, public static getInstance() method with double-checked locking. Or use enum (simplest, thread-safe): enum Singleton { INSTANCE; }. getInstance() should check if instance is null before creating.', 9),
('java', 'What is Java 8''s Stream API?', 'Streams process collections in a functional style. Intermediate operations (lazy): filter(), map(), sorted(), distinct(). Terminal operations (trigger execution): collect(), forEach(), reduce(), count(). Example: list.stream().filter(x->x>0).map(x->x*2).collect(Collectors.toList()). Do not confuse with I/O streams.', 10),
('java', 'What is HashMap and how does it work internally?', 'HashMap stores key-value pairs using hashing. When you put(key, value): computes key.hashCode() → maps to a bucket. Collisions handled by chaining (LinkedList/TreeNode in same bucket). Get performance: O(1) average, O(n) worst. Not thread-safe — use ConcurrentHashMap for thread safety.', 11),
('java', 'What are SOLID principles?', 'S — Single Responsibility: one reason to change. O — Open/Closed: open for extension, closed for modification. L — Liskov Substitution: subclass can replace parent without breaking behavior. I — Interface Segregation: small specific interfaces over large general ones. D — Dependency Inversion: depend on abstractions not concretions.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('cpp', 'What is a pointer vs a reference?', 'Pointer: holds memory address, can be null, can be reassigned, needs dereferencing (*ptr). Reference: alias for an existing variable, cannot be null, cannot be reassigned after initialization, no dereferencing needed. Use references when you know the variable always exists; pointers when you need optional or dynamic targets.', 1),
('cpp', 'What is memory management in C++?', 'Manually allocate with new, deallocate with delete (new[] / delete[] for arrays). Forgetting delete → memory leak. Deleting twice → undefined behavior. Smart pointers (C++11) automate this: unique_ptr (sole ownership, auto-deleted), shared_ptr (shared ownership, reference counted), weak_ptr (non-owning reference). Prefer smart pointers.', 2),
('cpp', 'What is the difference between struct and class in C++?', 'The only difference: struct members are public by default; class members are private by default. Conventionally: struct for plain data (no methods/logic), class for objects with behavior. Both can have constructors, methods, inheritance, and access specifiers.', 3),
('cpp', 'What is a virtual function?', 'A virtual function enables runtime polymorphism (dynamic dispatch). Base class declares virtual void draw(); derived class overrides it. Calling draw() on a Base* that points to a Derived object calls Derived::draw(). Pure virtual (= 0) makes the class abstract. The vtable stores function pointers for this lookup.', 4),
('cpp', 'What is RAII?', 'Resource Acquisition Is Initialization: tie resource lifetime to object lifetime. Acquire resource in constructor, release in destructor. The destructor is always called when object goes out of scope — even during exceptions. Examples: std::fstream, std::lock_guard, smart pointers. Eliminates resource leaks.', 5),
('cpp', 'What is the STL?', 'Standard Template Library provides: Containers (vector, list, map, set, queue, stack, unordered_map), Algorithms (sort, find, count, transform, accumulate), Iterators (bridge between containers and algorithms). Templates make it generic. Example: std::sort(vec.begin(), vec.end()).', 6),
('cpp', 'What are move semantics and rvalue references?', 'Move semantics (C++11) transfers ownership of resources instead of copying them. Rvalue reference (&&) binds to temporary objects. std::move() casts to rvalue, enabling the move constructor/assignment. Critical for performance with large objects like vectors — avoids deep copies when returning from functions or inserting temporaries.', 7),
('cpp', 'What is a template?', 'Templates enable generic programming. Function template: template<typename T> T max(T a, T b) { return a > b ? a : b; }. Class template: template<typename T> class Stack {}. Compiled at instantiation time — one version per type used. STL containers are all templates.', 8),
('cpp', 'What is undefined behavior?', 'Code that the C++ standard does not define — the compiler can do anything: crash, produce wrong results, appear to work, or vary between builds. Common causes: dereferencing null/dangling pointer, signed integer overflow, reading uninitialized memory, out-of-bounds array access. Use sanitizers (-fsanitize=address,undefined) to catch it.', 9),
('cpp', 'What is the difference between stack and heap memory?', 'Stack: automatic storage, fast allocation/deallocation (just move stack pointer), limited size (~1–8MB), variables auto-freed when scope exits. Heap: manual allocation (new/malloc), slower, much larger, programmer controls lifetime. Stack overflow occurs with deep recursion. Large data should go on the heap.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('c', 'What is a pointer in C?', 'A pointer is a variable that stores the memory address of another variable. Declared as int *p;. Assign with p = &var (address-of). Dereference with *p (value at address). Pointers enable dynamic memory allocation, arrays, and passing by reference. NULL pointer points to address 0.', 1),
('c', 'What is the difference between malloc and calloc?', 'malloc(size): allocates size bytes, contents are uninitialized (garbage values). calloc(n, size): allocates n*size bytes, initializes all bytes to zero. Both return void* (must cast). realloc() resizes existing allocation. Always check for NULL return and call free() when done to avoid memory leaks.', 2),
('c', 'What is a dangling pointer?', 'A pointer that points to memory that has been freed or gone out of scope. Dereferencing it causes undefined behavior. Prevention: set pointer to NULL after free(). Example: int *p = malloc(4); free(p); *p = 5; // dangling — undefined. p = NULL; // safe from here.', 3),
('c', 'What is the difference between stack and heap?', 'Stack: local variables and function call frames, auto-managed, limited size, fast. Heap: dynamic memory via malloc/calloc, manually managed with free(), large size, slower. Stack overflow: too deep recursion. Memory leak: heap memory allocated but never freed.', 4),
('c', 'What does the static keyword do in C?', 'Inside a function: variable retains its value between calls (stored in data segment, not stack). Outside a function (file scope): variable/function is only visible within that translation unit (internal linkage). As a function parameter on arrays: tells compiler the pointer is non-null and has at least N elements.', 5),
('c', 'What is a function pointer?', 'A pointer that holds the address of a function, allowing it to be passed around and called dynamically. Syntax: int (*fp)(int, int) = &add; fp(3, 4). Used in callbacks (qsort''s comparator), event systems, and implementing polymorphism in C. The basis of qsort(), signal(), and other C standard library functions.', 6),
('c', 'What is the difference between struct and union?', 'Struct: all members exist simultaneously, total size = sum of members (+ padding). Union: all members share the same memory, size = largest member. Useful when you need to interpret the same bytes as different types. Only one member of a union should be active at a time.', 7),
('c', 'What are preprocessor directives?', '#include inserts file contents. #define creates macros (text substitution). #ifdef/#ifndef/#endif for conditional compilation. #pragma for compiler hints. Macros have no type checking — prefer const and inline functions. Include guards (#ifndef HEADER_H #define HEADER_H ... #endif) prevent double-inclusion.', 8),
('c', 'What is the volatile keyword?', 'volatile tells the compiler not to optimize reads/writes of a variable — always read it from memory, not a cached register. Used for: hardware memory-mapped I/O registers, variables modified by signal handlers or interrupt routines. Note: volatile alone is not sufficient for thread safety.', 9),
('c', 'What is the difference between #include <file> and #include "file"?', '<file>: searches system/compiler include directories first (standard library headers). "file": searches the current directory first, then system directories (your own headers). Use <> for standard/library headers (stdio.h, stdlib.h), use "" for project-local headers.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('react', 'What is the Virtual DOM?', 'React keeps a lightweight in-memory copy of the real DOM (the Virtual DOM). When state changes, React re-renders the Virtual DOM, diffs it against the previous version (reconciliation), and only updates the real DOM where things changed. This batching and diffing makes React faster than direct DOM manipulation for complex UIs.', 1),
('react', 'What are React Hooks?', 'Hooks let functional components use state and lifecycle features. Core hooks: useState (local state), useEffect (side effects/lifecycle), useContext (consume context), useRef (mutable ref without re-render), useMemo (memoize expensive computation), useCallback (memoize functions), useReducer (complex state logic).', 2),
('react', 'Explain useState vs useReducer.', 'useState: simple independent values (numbers, strings, booleans). useReducer: complex state with multiple sub-values or when next state depends on previous (like Redux). useReducer(reducer, initialState) returns [state, dispatch]. Better when state transitions follow clear actions (SET_NAME, INCREMENT, RESET).', 3),
('react', 'What is useEffect and how does it work?', 'useEffect runs side effects after render. Dependency array controls when it runs: [] (once on mount), [a, b] (when a or b change), no array (every render). Return a cleanup function to handle unsubscribes/timers. Runs asynchronously after paint — use useLayoutEffect for synchronous DOM reads.', 4),
('react', 'What is the difference between useMemo and useCallback?', 'useMemo memoizes the return value of a function — recomputes only when deps change. Used for expensive calculations. useCallback memoizes the function itself — returns the same function reference between renders. Used to prevent child re-renders when passing callbacks as props. Both take a deps array.', 5),
('react', 'What are keys in React and why are they important?', 'Keys uniquely identify list items so React can track which items changed, were added, or removed during reconciliation. Without keys, React may re-render the wrong items or lose state. Use stable unique IDs (not array indices) as keys. Key must be unique among siblings, not globally.', 6),
('react', 'What is React Context?', 'Context provides a way to pass data through the component tree without prop drilling. Create with createContext(), provide with <Context.Provider value={...}>, consume with useContext(Context). Avoid for high-frequency state (re-renders all consumers). Use for themes, auth state, language — data that rarely changes.', 7),
('react', 'What is React.memo?', 'React.memo is a higher-order component that memoizes a functional component — it skips re-rendering if props have not changed (shallow comparison). const MyComp = React.memo(({ value }) => <div>{value}</div>). Use when a component is expensive to render and its parent re-renders often with unchanged props.', 8),
('react', 'What is lazy loading in React?', 'React.lazy(() => import(''./Component'')) enables code splitting — the component bundle is loaded only when first rendered. Wrap with <Suspense fallback={<Loading/>}> to show a fallback while loading. Reduces initial bundle size. Works well with route-level components in React Router.', 9),
('react', 'What is prop drilling and how to avoid it?', 'Prop drilling is passing props through many intermediate components just to reach a deeply nested child. Avoid it with: React Context (for global/shared state), component composition (pass components as props), state management (Redux, Zustand) for app-wide state.', 10),
('react', 'What are controlled vs uncontrolled components?', 'Controlled: form element value is driven by React state. Every keystroke updates state. const [val, setVal] = useState(""); <input value={val} onChange={e=>setVal(e.target.value)}/>. Uncontrolled: form stores its own state in the DOM, accessed via ref. Controlled is preferred for validation and consistency.', 11),
('react', 'What is the component lifecycle in React?', 'Mounting: constructor → render → DOM update → useEffect([]). Updating: render → DOM update → useEffect (deps changed), cleanup of previous effect runs first. Unmounting: useEffect cleanup function runs. In class components: componentDidMount, componentDidUpdate, componentWillUnmount map to these phases.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('nodejs', 'What is Node.js and how does it work?', 'Node.js is a JavaScript runtime built on Chrome''s V8 engine for server-side code. It uses an event-driven, non-blocking I/O model. When an async operation (file read, DB query) is requested, Node.js registers a callback and continues processing other requests — the OS notifies Node.js when the operation completes.', 1),
('nodejs', 'What is the Node.js event loop?', 'The event loop has phases: timers (setTimeout/setInterval) → I/O callbacks → idle/prepare → poll (wait for and execute I/O callbacks) → check (setImmediate callbacks) → close callbacks. Between each phase, process.nextTick queue and Promise microtasks run completely. It enables high concurrency with one thread.', 2),
('nodejs', 'What is middleware in Express.js?', 'Middleware is a function with access to req, res, and next. It runs in sequence for each request. Use for: logging, auth checking, body parsing, error handling. app.use(myMiddleware). Call next() to pass to next middleware. Order matters — middleware runs top-to-bottom. Error middleware has 4 params: (err, req, res, next).', 3),
('nodejs', 'What is the difference between process.nextTick and setImmediate?', 'process.nextTick runs after the current operation completes, before the next event loop iteration — even before I/O callbacks. setImmediate runs in the check phase of the next event loop iteration, after I/O. Prefer setImmediate to avoid starving the event loop with recursive nextTick calls.', 4),
('nodejs', 'What are streams in Node.js?', 'Streams process data in chunks instead of loading it all into memory. Types: Readable (fs.createReadStream), Writable (fs.createWriteStream), Duplex (TCP socket), Transform (compression/encryption). Pipe: readable.pipe(writable). Events: data, end, error. Essential for handling large files efficiently.', 5),
('nodejs', 'What is the cluster module?', 'Node.js runs on one CPU core by default. The cluster module forks multiple worker processes (one per CPU core) that share the same server port. The master process distributes incoming connections to workers. Together with PM2 (which uses clustering internally), this maximizes multi-core server performance.', 6),
('nodejs', 'What is CommonJS vs ES Modules?', 'CommonJS (Node.js default): require() / module.exports. Synchronous, dynamic imports possible. ES Modules: import / export. Asynchronous, static analysis enables tree-shaking. Node.js supports both: .cjs or package.json type:"commonjs" for CJS; .mjs or type:"module" for ESM. ESM is the modern standard.', 7),
('nodejs', 'How do you handle errors in async Node.js code?', 'Callbacks: error-first convention cb(err, data). Promises: .catch() or try/catch with async/await. Express async errors: wrap handlers with try/catch and call next(err). Unhandled rejections: process.on(''unhandledRejection'', handler). Always handle errors — unhandled ones crash the process.', 8),
('nodejs', 'What is CORS and how do you enable it in Express?', 'CORS (Cross-Origin Resource Sharing) is a browser security policy that blocks requests from different origins. Server must send Access-Control-Allow-Origin header. In Express: npm install cors, then app.use(cors()) for all origins or cors({ origin: ''https://yourdomain.com'' }) for a specific one.', 9),
('nodejs', 'What is the event emitter pattern?', 'Node.js EventEmitter allows objects to emit named events and register listeners. const emitter = new EventEmitter(); emitter.on(''data'', callback); emitter.emit(''data'', payload). Many Node.js core APIs (http.Server, stream.Readable) extend EventEmitter. Use removeListener() to prevent memory leaks from long-lived listeners.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('redux', 'What is Redux and when should you use it?', 'Redux is a predictable state container for JavaScript apps. Use it when: multiple unrelated components need the same data, prop drilling becomes painful, complex state logic with many actions, or you need time-travel debugging. For simple apps or state local to a component tree, React Context or useState is enough.', 1),
('redux', 'Explain the Redux data flow.', 'Three principles: (1) Single source of truth — one store holds all state. (2) State is read-only — only actions can trigger changes. (3) Changes are made with pure functions (reducers). Flow: Component dispatches Action → Reducer receives (state, action) and returns new state → Store updates → Component re-renders.', 2),
('redux', 'What is a reducer?', 'A pure function that takes (currentState, action) and returns a new state. Must be pure: no side effects, no mutation, same input always gives same output. switch on action.type. Return the current state for unknown actions. In Redux Toolkit, use createSlice which wraps reducers with Immer for safe mutation syntax.', 3),
('redux', 'What is Redux Thunk?', 'Redux Thunk is middleware that lets you dispatch functions (thunks) instead of plain objects. The function receives dispatch and getState. Used for async actions: fetch data → dispatch loading action → fetch resolves → dispatch success/failure action. Redux Toolkit''s createAsyncThunk simplifies this pattern.', 4),
('redux', 'What is Redux Toolkit (RTK)?', 'The official recommended way to write Redux. Reduces boilerplate significantly. Key APIs: configureStore() (sets up store with DevTools and Thunk), createSlice() (generates actions and reducers together with Immer), createAsyncThunk() (handles async logic), RTK Query (data fetching and caching). Always prefer RTK over manual Redux.', 5),
('redux', 'What is useSelector and useDispatch?', 'useSelector(selector) reads state from the Redux store — re-renders only when the selected value changes. const count = useSelector(state => state.counter.value). useDispatch() returns the store''s dispatch function. const dispatch = useDispatch(); dispatch(increment()). These hooks replaced connect() from older Redux.', 6),
('redux', 'What is a selector and why use them?', 'A selector is a function that extracts and transforms data from the Redux store. Using createSelector from Reselect: memoizes derived state — only recomputes when inputs change. Keeps components decoupled from store shape. If store structure changes, update the selector, not every component.', 7),
('redux', 'What is Redux middleware?', 'Middleware sits between dispatching an action and the reducer receiving it. It can log, delay, transform, or intercept actions. Applied with applyMiddleware(). Common: redux-thunk (async), redux-logger (console logs all actions/state). Middleware chain: dispatch → middleware1 → middleware2 → reducer.', 8),
('redux', 'How do you handle API calls with Redux Toolkit?', 'Use createAsyncThunk: const fetchUser = createAsyncThunk(''user/fetch'', async (id) => { const res = await fetch(''/api/user/''+id); return res.json(); }). In createSlice, handle states with extraReducers using builder: addCase(fetchUser.pending, ...), addCase(fetchUser.fulfilled, ...), addCase(fetchUser.rejected, ...).', 9),
('redux', 'What is the difference between Redux and Context API?', 'Context: built-in, no extra library, re-renders all consumers on any change, no devtools. Redux: external library, fine-grained updates via selectors, excellent DevTools with time-travel, middleware support. For apps with complex frequently-updated global state: Redux. For theme, auth, language: Context is enough.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('html', 'What is semantic HTML?', 'Semantic HTML uses elements that describe their meaning: header, nav, main, article, section, aside, footer. Opposed to div for everything. Benefits: better accessibility (screen readers understand structure), better SEO (search engines understand content hierarchy), more maintainable code.', 1),
('html', 'What is the difference between block and inline elements?', 'Block elements (div, p, h1–h6, ul, section): start on new line, take full width, can contain other block/inline elements. Inline elements (span, a, strong, img): flow within text, only take as much width as needed, can only contain inline elements (with some exceptions like img).', 2),
('html', 'What are HTML meta tags?', 'Meta tags provide metadata not visible on the page. charset="UTF-8" (character encoding), viewport content="width=device-width, initial-scale=1" (responsive design), name="description" (SEO), og:title property (Open Graph for social sharing). All placed in the head section.', 3),
('html', 'What are data attributes?', 'data-* attributes store custom data on HTML elements: <div data-user-id="42" data-role="admin">. Access in JS: element.dataset.userId (auto-camelCased). Useful for storing information without extra DOM structure or hidden inputs. Visible in DevTools, not recommended for sensitive data.', 4),
('html', 'What is accessibility (a11y) in HTML?', 'Making web content usable by people with disabilities. Key practices: semantic HTML, alt text on images, ARIA labels for interactive elements, keyboard navigability (tabIndex, focus management), sufficient color contrast, visible focus indicators, captions for video. Use Lighthouse audit to check your score.', 5),
('html', 'What is the difference between localStorage and sessionStorage?', 'Both are Web Storage APIs storing key-value strings. localStorage: persists until explicitly cleared, shared across all tabs of the same origin. sessionStorage: cleared when the browser tab closes, isolated per tab. Both have ~5–10MB limit. Use cookies for server-readable data.', 6),
('html', 'What are HTML forms and form validation?', 'Forms collect user input: <form action="/submit" method="POST">. Input types: text, email, password, number, date, file, checkbox, radio. Built-in validation: required, minlength, maxlength, pattern (regex), type="email". Access form data server-side or with FormData API in JS. preventDefault() to handle with JS.', 7),
('html', 'What is the difference between GET and POST methods?', 'GET: parameters in URL, bookmarkable, cached, idempotent, max URL length limit. Use for fetching data. POST: data in request body, not cached, not bookmarkable, no size limit. Use for sending/changing data. Never send sensitive data via GET — it is visible in URL, logs, and browser history.', 8),
('html', 'What are void elements in HTML?', 'Void elements have no closing tag and no content: br, img, input, hr, link, meta, area, base, col, embed, source, track, wbr. In HTML5, self-closing slash is optional (br/ or br). Do not write /br — it is invalid HTML.', 9),
('html', 'What is an iframe?', 'iframe embeds another HTML document within the current page. Used for embedding YouTube videos, maps, payment forms. Security concern: clickjacking. Defend with X-Frame-Options header or frame-ancestors CSP. The sandbox attribute restricts capabilities. Cross-origin iframes cannot access parent''s DOM (same-origin policy).', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('css', 'What is the CSS box model?', 'Every element is a box with: Content (text/children) → Padding (space inside border) → Border → Margin (space outside border). By default (content-box), width = content width. With box-sizing: border-box (recommended), width includes padding and border. Set * { box-sizing: border-box; } globally.', 1),
('css', 'What is Flexbox?', 'Flexbox is a 1D layout model for arranging items in a row or column. Container: display: flex; flex-direction: row|column; justify-content (main axis alignment); align-items (cross axis alignment); flex-wrap; gap. Items: flex-grow, flex-shrink, flex-basis, align-self, order. Best for navigation bars, card rows, centering elements.', 2),
('css', 'What is CSS Grid?', 'Grid is a 2D layout model for rows AND columns simultaneously. Container: display: grid; grid-template-columns: repeat(3, 1fr); grid-template-rows; gap; grid-template-areas. Items: grid-column, grid-row, grid-area. Best for page layouts and complex 2D patterns. Use Flexbox inside Grid cells for inner arrangement.', 3),
('css', 'What is CSS specificity?', 'Specificity determines which rule applies when multiple rules target the same element. Hierarchy: !important > inline styles (1000) > IDs (#id = 100) > classes/attributes (.class, [attr] = 10) > elements/pseudo-elements (tag = 1). Equal specificity: last rule wins. Avoid !important — use more specific selectors instead.', 4),
('css', 'What are CSS custom properties (variables)?', 'Define: --color-primary: #3b82f6; in :root {} (global scope). Use: color: var(--color-primary);. Can be overridden per component or with media queries. Can be updated with JavaScript. Unlike Sass variables, they exist at runtime. Make theming (dark mode) easy: update variables in [data-theme="dark"] {}.', 5),
('css', 'What is the difference between relative, absolute, fixed, and sticky positioning?', 'static: default flow. relative: offset from its normal position, still in flow. absolute: removed from flow, positioned relative to nearest non-static ancestor. fixed: removed from flow, positioned relative to viewport (stays on scroll). sticky: in flow until scroll threshold, then acts fixed. Use relative on parent of absolute children.', 6),
('css', 'What is z-index?', 'z-index controls stacking order on the z-axis (front/back). Only works on positioned elements (not static). Higher value = in front. Creates a stacking context: a positioned element with z-index creates a new context — its children''s z-indexes are relative to it, not the page root. Common gotcha: z-index:9999 still renders behind a lower z-index stacking context parent.', 7),
('css', 'What are CSS media queries?', '@media (max-width: 768px) {} applies styles only when conditions match. Common breakpoints: 480px (mobile), 768px (tablet), 1024px (desktop). Mobile-first: write base styles for mobile, add @media (min-width: ...) for larger screens. Also: @media (prefers-color-scheme: dark), (prefers-reduced-motion: reduce).', 8),
('css', 'What is BEM (Block, Element, Modifier)?', 'BEM is a CSS naming methodology for scalable, readable class names. Block: .card. Element (part of block): .card__title, .card__image. Modifier (variation): .card--featured, .card__title--large. Benefits: low specificity (all single classes), self-documenting, no nesting conflicts. Popular in large codebases without CSS Modules.', 9),
('css', 'What is the difference between display: none and visibility: hidden?', 'display: none: element is completely removed from layout — takes no space, invisible. visibility: hidden: element is invisible but still occupies its space in the layout. opacity: 0: visually invisible but still occupies space and receives pointer events. Use display:none to truly hide; visibility:hidden when you need to preserve layout space.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('sql', 'What are SQL JOINs? Explain each type.', 'INNER JOIN: rows where condition matches in BOTH tables. LEFT JOIN: all rows from left table + matching rows from right (NULLs for no match). RIGHT JOIN: opposite of LEFT. FULL OUTER JOIN: all rows from both tables (NULLs where no match). CROSS JOIN: cartesian product of all rows. SELF JOIN: table joined to itself (used for hierarchies or comparing rows).', 1),
('sql', 'What is database normalization?', 'Normalization reduces redundancy and dependency. 1NF: atomic values, no repeating groups. 2NF: 1NF + no partial dependency (non-key attributes depend on whole primary key). 3NF: 2NF + no transitive dependency (non-key does not depend on another non-key). Denormalize intentionally for read performance when needed.', 2),
('sql', 'What is an index and how does it work?', 'An index is a data structure (usually B-tree) that speeds up data retrieval. Without index: full table scan O(n). With index: O(log n). Tradeoff: faster reads but slower writes (index must be updated on insert/update/delete). Create on: frequently searched columns, JOIN columns, ORDER BY columns. Avoid indexing small tables or very low-cardinality columns.', 3),
('sql', 'What are ACID properties?', 'Atomicity: all operations in a transaction succeed or all fail (no partial). Consistency: transaction brings DB from one valid state to another. Isolation: concurrent transactions do not interfere with each other. Durability: committed transactions survive crashes (written to disk). ACID guarantees make relational databases reliable for financial systems.', 4),
('sql', 'What is the difference between WHERE and HAVING?', 'WHERE filters rows before aggregation — cannot use aggregate functions. HAVING filters after GROUP BY — used with aggregate functions. Example: SELECT dept, COUNT(*) FROM employees WHERE active=1 GROUP BY dept HAVING COUNT(*) > 5; — WHERE filters active employees, HAVING filters departments with more than 5 employees.', 5),
('sql', 'What is the difference between DELETE, TRUNCATE, and DROP?', 'DELETE: removes specific rows (WHERE clause), can be rolled back, fires triggers, slow for large tables. TRUNCATE: removes all rows, cannot use WHERE, faster (not logged row-by-row), resets identity/auto-increment, can be rolled back in some DBs. DROP: removes the entire table structure. Cannot be rolled back.', 6),
('sql', 'What is a stored procedure?', 'A stored procedure is precompiled SQL code stored in the database that can be called by name. Benefits: performance (precompiled), reusability, reduced network traffic, security (grant execute without table access). CREATE PROCEDURE GetUser(@id INT) AS SELECT * FROM users WHERE id=@id. Called with EXEC GetUser 42.', 7),
('sql', 'What is a subquery vs a JOIN?', 'Subquery: a query nested inside another. Can be in SELECT (scalar), FROM (derived table), or WHERE (correlated). JOINs are usually more performant as the optimizer handles them better. Correlated subquery runs once per outer row — often replaceable with a JOIN. Use subquery when result is conceptually separate from the main query.', 8),
('sql', 'What is a view?', 'A view is a named SQL query stored in the DB that acts like a virtual table. SELECT * FROM active_users uses the view definition behind the scenes. Benefits: simplify complex queries, restrict data access, hide business logic. Materialized views store the results physically for better read performance but need refresh.', 9),
('sql', 'What are transactions and how do you use them?', 'BEGIN TRANSACTION; ... COMMIT; groups multiple SQL statements into one atomic unit. ROLLBACK; undoes all changes if something fails. Isolation levels control how transactions interact: READ UNCOMMITTED, READ COMMITTED, REPEATABLE READ, SERIALIZABLE (most isolated). Higher isolation = fewer anomalies but more locking and lower throughput.', 10),
('sql', 'What is GROUP BY?', 'GROUP BY groups rows with the same value in specified columns so aggregate functions (COUNT, SUM, AVG, MAX, MIN) operate on each group. Example: SELECT category, AVG(price) FROM products GROUP BY category. Every column in SELECT must be either in GROUP BY or wrapped in an aggregate function (else error in strict mode).', 11),
('sql', 'What is a primary key vs a foreign key?', 'Primary key: uniquely identifies each row, must be unique and NOT NULL, one per table. Often auto-incremented integer or UUID. Foreign key: a column that references the primary key of another table, enforcing referential integrity. Deleting a referenced row raises FK violation unless ON DELETE CASCADE or ON DELETE SET NULL is configured.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('mongodb', 'What is MongoDB and when should you use it?', 'MongoDB is a NoSQL document database that stores data as JSON-like BSON documents. Use it when: schema is flexible or evolving, data is hierarchical/nested, horizontal scaling is needed, you are storing unstructured or semi-structured data. Not ideal for: complex multi-table transactions, strict relational data, heavy aggregation joins.', 1),
('mongodb', 'What is a document in MongoDB?', 'A document is a JSON-like record (stored as BSON). It is the basic unit of data, equivalent to a row in SQL. Documents in the same collection can have different fields (schema-less). Example: { _id: ObjectId("..."), name: "Alice", skills: ["React", "Node"], address: { city: "Mumbai" } }. _id is the auto-generated primary key.', 2),
('mongodb', 'What is aggregation in MongoDB?', 'The aggregation pipeline processes documents through stages. Common stages: $match (filter — like WHERE), $group (aggregate — like GROUP BY), $project (reshape document), $sort, $limit, $lookup (JOIN between collections), $unwind (flatten arrays). Example: db.orders.aggregate([$match:{status:"paid"}, $group:{_id:"$user", total:{$sum:"$amount"}}]).', 3),
('mongodb', 'What is an index in MongoDB?', 'Indexes speed up queries. Without: full collection scan. With: O(log n). db.users.createIndex({ email: 1 }) creates ascending index on email. Common types: single field, compound, text (full-text search), geospatial, TTL (auto-delete documents after N seconds). Use .explain("executionStats") to verify if index is used.', 4),
('mongodb', 'What is the difference between find() and findOne()?', 'find() returns a Cursor of all matching documents — iterate with forEach or toArray(). findOne() returns the first matching document as a plain object (or null). Both accept a filter object and a projection. findOne() is slightly more efficient when you only need one document. Example: db.users.findOne({email:"a@b.com"}, {name:1, _id:0}).', 5),
('mongodb', 'What is a replica set?', 'A replica set is a group of MongoDB servers that maintain the same data. One primary (accepts writes), multiple secondaries (replicate from primary, can serve reads). If the primary fails, secondaries elect a new primary automatically — high availability. Minimum 3 nodes recommended for automatic failover.', 6),
('mongodb', 'What is sharding in MongoDB?', 'Sharding horizontally partitions data across multiple servers (shards) for scalability. Each shard holds a subset of the data based on a shard key. A mongos router directs queries to the right shard(s). Choose shard key carefully — needs high cardinality, even distribution, rarely updated. A bad shard key creates hotspots.', 7),
('mongodb', 'What is the difference between SQL and NoSQL?', 'SQL: fixed schema, tables with rows, ACID transactions, complex JOINs, vertically scalable, great for relational structured data. NoSQL: flexible schema, various data models (document, key-value, graph, columnar), horizontal scalability, eventual consistency by default, great for large scale or unstructured data. Neither is universally better.', 8),
('mongodb', 'What are MongoDB''s CRUD operations?', 'Create: insertOne({...}), insertMany([...]). Read: find(filter, projection), findOne(). Update: updateOne(filter, {$set:{field:value}}), updateMany(), replaceOne(). Delete: deleteOne(filter), deleteMany(). Common update operators: $set, $inc, $push, $pull, $unset. findOneAndUpdate() atomically finds and updates in one operation.', 9),
('mongodb', 'What is the ObjectId in MongoDB?', 'ObjectId is the default _id type — a 12-byte BSON value. Composition: 4 bytes timestamp + 5 bytes random value + 3 bytes incrementing counter. This makes ObjectIds naturally sortable by creation time. new ObjectId().getTimestamp() returns the creation date. MongoDB creates _id automatically if you do not provide one.', 10);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('dsa_general', 'What is Big O notation?', 'Big O describes algorithm efficiency — how time/space grows with input size n. Common complexities: O(1) constant, O(log n) binary search, O(n) linear scan, O(n log n) merge sort, O(n²) nested loops, O(2ⁿ) exponential recursion. Focus on dominant term, drop constants. Always analyze worst case unless stated otherwise.', 1),
('dsa_general', 'What is a linked list? Types?', 'A linked list is a sequence of nodes where each node holds data and a pointer to the next node. O(1) insert/delete at head, O(n) random access (no indexing). Types: Singly linked (next pointer only), Doubly linked (next + prev pointer, enables backward traversal), Circular linked (last node points back to head).', 2),
('dsa_general', 'What is a binary search tree (BST)?', 'A BST is a tree where left child < node < right child for every node. Search/insert/delete: O(log n) average, O(n) worst case (skewed tree). To avoid skew: use self-balancing trees (AVL tree, Red-Black tree). In-order traversal of a BST gives sorted output. BST is the base of many tree interview problems.', 3),
('dsa_general', 'What is dynamic programming?', 'DP solves complex problems by breaking them into overlapping subproblems and storing results (memoization = top-down, tabulation = bottom-up). If a problem has optimal substructure + overlapping subproblems → DP. Classic problems: Fibonacci, longest common subsequence, knapsack, coin change, edit distance, longest increasing subsequence.', 4),
('dsa_general', 'What is BFS vs DFS?', 'BFS (Breadth-First Search): explores level by level using a Queue. Finds shortest path in unweighted graphs. O(V+E). DFS (Depth-First Search): explores as deep as possible using a Stack (or recursion). Used for: cycle detection, topological sort, connected components, solving mazes. Both are O(V+E) time.', 5),
('dsa_general', 'What is a hash table?', 'A hash table stores key-value pairs. hash(key) maps to a bucket index. O(1) average insert/search/delete. Collisions handled by chaining (linked list at each bucket) or open addressing (linear/quadratic probing). Load factor = n/capacity. When > 0.7, resize (rehash). Implemented as HashMap in Java, dict in Python, Map in JS.', 6),
('dsa_general', 'What is the two-pointer technique?', 'Use two pointers (indices) moving toward each other or in the same direction to solve problems in O(n) instead of O(n²). Examples: check palindrome, find pair summing to target in sorted array, container with most water, remove duplicates from sorted array. Works best when array is sorted or when shrinking a window helps.', 7),
('dsa_general', 'What is the sliding window technique?', 'Maintain a window (subarray/substring) that slides over data. Grow window by moving right pointer, shrink by moving left when a constraint is violated. Reduces O(n²) nested loops to O(n). Examples: longest substring without repeating characters, max sum subarray of size k, minimum window substring.', 8),
('dsa_general', 'What is quicksort? What is its time complexity?', 'Quicksort picks a pivot, partitions array so elements < pivot are left, > pivot are right, then recursively sorts each side. Average O(n log n), worst O(n²) when pivot is always smallest/largest (avoid with random pivot or median-of-three). In-place (O(log n) stack space). Usually faster than merge sort in practice due to cache efficiency.', 9),
('dsa_general', 'What is binary search?', 'Binary search finds an element in a sorted array in O(log n). Start with lo=0, hi=n-1. Mid = lo + (hi-lo)/2. If arr[mid]==target: found. If arr[mid]<target: lo=mid+1. Else: hi=mid-1. Common mistakes: infinite loop (wrong lo/hi update), overflow (do not use (lo+hi)/2 with large integers).', 10),
('dsa_general', 'What is a heap (priority queue)?', 'A heap is a complete binary tree where parent >= children (max-heap) or parent <= children (min-heap). Insert/delete: O(log n). Get max/min: O(1). Implemented as an array: parent at index i, children at 2i+1 and 2i+2. Used for: top-K elements, Dijkstra''s algorithm, median of data stream, task scheduling.', 11),
('dsa_general', 'What is a graph? How do you represent one?', 'A graph has vertices (nodes) and edges (connections). Can be directed or undirected, weighted or unweighted, cyclic or acyclic. Representations: Adjacency matrix (V×V, O(V²) space, O(1) edge lookup), Adjacency list (array of lists, O(V+E) space — preferred for sparse graphs). Key algorithms: BFS, DFS, Dijkstra, Bellman-Ford, Kruskal, Prim.', 12),
('dsa_general', 'What is recursion and when should you use it?', 'Recursion is when a function calls itself with a smaller subproblem. Must have a base case (termination condition). Uses call stack — deep recursion can cause stack overflow. Good for: tree/graph traversal, divide and conquer, backtracking (permutations, N-queens, sudoku). Convert to iteration when stack depth is a concern.', 13),
('dsa_general', 'What is a stack and a queue?', 'Stack: LIFO (Last In First Out). push/pop from top. O(1) for both. Used for: function call stack, undo operations, balanced parentheses, DFS. Queue: FIFO (First In First Out). enqueue to back, dequeue from front. O(1) for both. Used for: BFS, task scheduling, sliding window. Deque supports both ends.', 14),
('dsa_general', 'What is a trie?', 'A trie (prefix tree) stores strings where each node represents a character. Insert/search/delete: O(m) where m is string length. Great for: autocomplete, spell check, IP routing, word dictionaries. Words sharing prefixes share nodes, making it space-efficient for large vocabularies. Space complexity: O(ALPHABET_SIZE × m × n).', 15);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('system_design_general', 'How would you design a URL shortener (like bit.ly)?', 'Components: API server, database (URL mappings), cache (Redis for hot URLs), load balancer. Short URL = base62 encode a counter or hash of long URL. Flow: POST /shorten → generate short code → store in DB → return short URL. GET /abc → lookup in cache → DB fallback → 301/302 redirect. Handle collisions. Scale: partitioned DB + CDN.', 1),
('system_design_general', 'What is load balancing?', 'Load balancing distributes incoming traffic across multiple servers to prevent any single server from being overwhelmed. Algorithms: Round Robin, Least Connections, IP Hash (sticky sessions), Weighted. L4 (transport layer — TCP) vs L7 (application layer — HTTP, can route by URL/headers). Also provides failover if a server goes down. Tools: Nginx, HAProxy, AWS ELB.', 2),
('system_design_general', 'What is caching and what strategies exist?', 'Caching stores frequently accessed data in fast storage (Redis, Memcached) to reduce DB load. Strategies: Cache-aside (app checks cache, falls back to DB, writes to cache on miss), Write-through (write to cache + DB together), Write-back (write to cache, async to DB — fast writes, risk of data loss). Eviction: LRU, LFU. Set TTL to avoid stale data.', 3),
('system_design_general', 'What is CAP theorem?', 'In a distributed system, you can guarantee only 2 of 3: Consistency (all nodes see same data), Availability (every request gets a response), Partition Tolerance (system works despite network splits). Since network partitions always happen in practice, you choose CP (consistent but may reject requests — HBase) or AP (available but may return stale data — Cassandra, DynamoDB).', 4),
('system_design_general', 'What is the difference between microservices and monolith?', 'Monolith: single deployable unit, simple to develop/debug, scales as a whole. Microservices: multiple small independently deployable services, each with its own DB, communicate via API/message queue. Microservices enable: independent scaling, independent deployment, tech diversity. Overhead: network latency, distributed tracing, operational complexity. Do not start with microservices.', 5),
('system_design_general', 'What is database sharding?', 'Sharding horizontally partitions data across multiple database instances. Each shard holds a subset of rows. Shard by: user ID range (range-based), hash(user_id) % N (hash-based), geographic region. Benefits: horizontal scalability, reduced load per DB. Challenges: cross-shard queries are hard, rebalancing is complex. Use only when a single DB instance cannot handle the load.', 6),
('system_design_general', 'What is a message queue and when to use it?', 'A message queue (Kafka, RabbitMQ, SQS) decouples producers and consumers. Producer sends message to queue; consumer processes asynchronously. Benefits: handles traffic spikes (buffer), retry failed tasks, parallel processing, loose coupling. Use for: email sending, image resizing, order processing, event streaming. Kafka excels for event sourcing and high-throughput streaming.', 7),
('system_design_general', 'What is rate limiting?', 'Rate limiting restricts how many requests a client can make in a time window to prevent abuse/DDoS. Algorithms: Token Bucket (allows bursts), Leaky Bucket (fixed rate), Fixed Window Counter (simple, edge case at window boundary), Sliding Window Log (accurate but memory-heavy). Implement at API gateway or load balancer. Return HTTP 429 Too Many Requests.', 8),
('system_design_general', 'What is a CDN?', 'A Content Delivery Network caches static assets (images, JS, CSS, videos) on servers geographically close to users. User requests go to nearest CDN edge server instead of origin. Benefits: lower latency, reduced origin server load, DDoS protection. Use for: static files, media, SPAs. Origin pull: CDN fetches from origin on cache miss. Providers: Cloudflare, Fastly, AWS CloudFront.', 9),
('system_design_general', 'What is eventual consistency?', 'In distributed systems, eventual consistency means all nodes will eventually have the same data — but reads may temporarily return stale data. Opposed to strong consistency where all reads return the latest write. Examples: DNS propagation, social media likes, shopping cart in DynamoDB. Trade availability and performance for strict consistency. Acceptable for many real-world use cases.', 10),
('system_design_general', 'What is the difference between REST and GraphQL?', 'REST: multiple endpoints per resource, server defines response shape, over-fetching or under-fetching is common, easy caching (GET requests). GraphQL: single endpoint, client specifies exactly what data it needs, eliminates over/under-fetching, harder to cache by default, great for complex frontends with many data relationships. Use REST for simple APIs; GraphQL for complex client-driven queries.', 11),
('system_design_general', 'How do you design a notification system?', 'Components: notification service, user preference DB, push/email/SMS providers (FCM, APNS, SendGrid, Twilio), message queue for async delivery. Flow: trigger event → check user preferences → put message in queue → worker picks up → sends via appropriate provider → store notification in DB → mark delivered. Handle retries with exponential backoff. Rate-limit notifications per user to avoid spam.', 12);
INSERT INTO study_questions (topic_id, question, answer, sort_order) VALUES
('ai_concepts', 'What is the difference between AI, ML, and Deep Learning?', 'AI: broad field of making machines simulate human intelligence. ML: subset of AI where machines learn from data without being explicitly programmed (algorithms find patterns). Deep Learning: subset of ML using neural networks with many layers — excels at images, text, audio. All deep learning is ML; all ML is AI. They are nested subsets.', 1),
('ai_concepts', 'What is supervised vs unsupervised learning?', 'Supervised: trained on labeled data (input→output pairs). Goal: learn a mapping function. Examples: classification (spam/not spam), regression (house price prediction). Unsupervised: trained on unlabeled data. Goal: find hidden structure. Examples: clustering (K-means), dimensionality reduction (PCA), anomaly detection. Semi-supervised: some labeled, mostly unlabeled data.', 2),
('ai_concepts', 'What is overfitting and how do you prevent it?', 'Overfitting: model memorizes training data but fails to generalize to new data (high training accuracy, low test accuracy). Prevention: more training data, regularization (L1/L2 penalty terms), dropout layers, early stopping, cross-validation, simpler model architecture, data augmentation, batch normalization. Underfitting: model too simple — increase complexity or train longer.', 3),
('ai_concepts', 'What is gradient descent?', 'Gradient descent minimizes the loss function. Compute gradient (direction of steepest increase) of loss w.r.t. weights, update weights in opposite direction: w = w - learning_rate × gradient. Variants: SGD (one sample — noisy but fast), Mini-batch (subset of samples — balanced), Adam (adaptive learning rates per parameter — most popular in practice).', 4),
('ai_concepts', 'What is a neural network?', 'A neural network is layers of interconnected nodes (neurons). Input layer → hidden layers → output layer. Each neuron: weighted sum of inputs → activation function (ReLU, sigmoid, tanh) → output. Training: forward pass (predict) → compute loss → backpropagation (compute gradients) → gradient descent (update weights). More layers = deeper network = more expressive.', 5),
('ai_concepts', 'What is a Large Language Model (LLM)?', 'LLMs (GPT-4, Claude, Llama) are neural networks trained on massive text corpora to predict the next token. Architecture: transformer with self-attention. Scale (billions of parameters) enables emergent abilities: reasoning, code generation, summarization. Trained with pre-training (next-token prediction) + RLHF (human preference alignment). Output is probabilistic — same prompt can give different answers.', 6),
('ai_concepts', 'What is the Transformer architecture?', 'Transformers (2017, "Attention Is All You Need") replaced RNNs for NLP. Key mechanism: self-attention — every token attends to every other token, capturing long-range dependencies. Multi-head attention runs attention in parallel heads. Positional encoding adds sequence order info. Encoder (BERT) for understanding; Decoder (GPT) for generation; Encoder-Decoder (T5) for translation.', 7),
('ai_concepts', 'What is prompt engineering?', 'Prompt engineering is crafting inputs to LLMs to get desired outputs. Techniques: zero-shot (just ask), few-shot (give examples in the prompt), chain-of-thought (ask model to reason step-by-step), role prompting (act as an expert), system prompts (persistent instructions). Affects output quality significantly. Works best for well-defined tasks with clear success criteria.', 8),
('ai_concepts', 'What is RAG (Retrieval-Augmented Generation)?', 'RAG combines LLMs with a retrieval system to solve knowledge cutoff and private data limitations. When a query arrives: search a vector database (embeddings of your documents) for relevant chunks → inject those chunks into the LLM prompt as context → LLM generates answers grounded in retrieved facts. Reduces hallucination and keeps answers up-to-date.', 9),
('ai_concepts', 'What is a confusion matrix?', '2×2 matrix for binary classification. True Positive (predicted pos, actually pos), True Negative (predicted neg, actually neg), False Positive / Type I error (predicted pos, actually neg), False Negative / Type II error (predicted neg, actually pos). Metrics: Accuracy = (TP+TN)/total. Precision = TP/(TP+FP). Recall = TP/(TP+FN). F1 = 2×(Precision×Recall)/(Precision+Recall).', 10),
('ai_concepts', 'What is fine-tuning an LLM?', 'Fine-tuning continues training a pre-trained model on a smaller task-specific dataset to adapt its behavior. Full fine-tuning updates all weights — expensive. LoRA (Low-Rank Adaptation): adds small trainable matrices, only trains those — much cheaper (1–10% of full fine-tuning cost). Use fine-tuning when prompt engineering alone is insufficient for consistent specialized behavior.', 11),
('ai_concepts', 'What is a vector embedding?', 'Embeddings convert text (or images, audio) into dense numerical vectors (e.g. 1536 dimensions) that capture semantic meaning. Similar meanings → vectors close together in vector space (measured by cosine similarity). Generated by models like text-embedding-ada-002 or sentence-transformers. Used in: semantic search, recommendation systems, RAG pipelines, document clustering.', 12);
